#include <stdio.h>
#include <string.h>

void test_truncation(char *small, char *big) {
    int ret;
    ret = snprintf(small, 16, "Hello, %s! Score=%d", "clings", 100);
    ret = snprintf(big, 64, "Hello, %s! Score=%d", "clings", 100);
}

int build_path(char *path, size_t sz) {
    int written = 0;
    written += snprintf(path + written, sz - written, "/home/");
    written += snprintf(path + written, sz - written, "%s/", "user");
    written += snprintf(path + written, sz - written, "%s", "documents/files/report.txt");
    return written;
}

validation.test_code:
void test_small_truncated(void) {
    char small[16];
    test_truncation(small, NULL);
    TEST_ASSERT_EQUAL_INT(15, strlen(small));
    TEST_ASSERT_TRUE(strstr(small, "Hello"));
}

void test_big_complete(void) {
    char big[64];
    test_truncation(NULL, big);
    TEST_ASSERT_EQUAL_STRING("Hello, clings! Score=100", big);
}

void test_path_buildup(void) {
    char path[32];
    int written = build_path(path, sizeof(path));
    TEST_ASSERT_TRUE(written > 0);
    TEST_ASSERT_TRUE(strstr(path, "/home/"));
}

void test_path_content(void) {
    char path[32];
    build_path(path, sizeof(path));
    TEST_ASSERT_TRUE(strlen(path) > 0);
}

int main(void) {
    RUN_TEST(test_small_truncated);
    RUN_TEST(test_big_complete);
    RUN_TEST(test_path_buildup);
    RUN_TEST(test_path_content);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

